css_template:
#{{ID}} .rep-bottom-bar {
    position: absolute;
    bottom: 40px;
    left: 96px;
    width: var(--v-width, 1728px);
    height: 60px;
    background: {{{PRIMARY_BG}}};
    display: none;
    align-items: center;
    overflow: hidden;
    font-family: '{{FONT_FAMILY}}', sans-serif;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform-origin: left center;
    z-index: 5;
}
#{{ID}} .news-content-v8 {
    flex: 1;
    height: 100%;
    display: none;
    align-items: center;
    padding-left: 170px;
    overflow: hidden;
}
#{{ID}} .news-text-v8 {
    color: {{{TITLE_COLOR}}};
    font-size: {{FONT_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: uppercase;
    white-space: nowrap;
}
#{{ID}} .wiper-v8 {
    position: absolute;
    left: 0;
    width: auto;
    min-width: 150px;
    padding: 0 40px;
    height: 100%;
    background: {{{WIPER_BG}}};
    display: none;
    align-items: center;
    justify-content: center;
    box-shadow: 5px 0 15px rgba(0,0,0,0.5);
    z-index: 10;
    box-sizing: border-box;
    overflow: hidden;
}
#{{ID}} .wiper-v8-gleam {
    position: absolute;
    top: 0;
    left: -100%;
    width: 60%;
    height: 100%;
    display: {{#if WIPER_GLEAM_ENABLED}}block{{else}}none{{/if}};
    background: {{{WIPER_GLEAM_BG}}};
    transform: skewX(-20deg);
    pointer-events: none;
    animation: sweep-gleam-v8 {{WIPER_GLEAM_DURATION}}s infinite ease-in-out;
}
#{{ID}} .wiper-text-v8 {
    font-weight: {{WIPER_FONT_WEIGHT}};
    font-size: {{WIPER_FONT_SIZE}}px;
    font-family: {{WIPER_FONT}}, sans-serif;
    color: {{{WIPER_TEXT_COLOR}}};
    letter-spacing: {{WIPER_LETTER_SPACING}}px;
    position: relative;
    z-index: 11;
    white-space: nowrap;
}
@keyframes sweep-gleam-v8 {
    0% { left: -100%; }
    100% { left: 200%; }
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-bottom-bar");
    const newsTextEl = root.querySelector(".news-text-v8");
    const wiper = root.querySelector(".wiper-v8");
    const wiperTextEl = root.querySelector(".wiper-text-v8");
    const dataEl = root.querySelector("#f-news-list");
    if(!container || !dataEl) return;

    const DEFAULT_WIPER = "{{WIPER_TEXT}}";

    let newsList = [];
    try { newsList = JSON.parse(dataEl.innerHTML || "[]"); } catch(e) {}

    let currentIndex = 0;
    let cycleTimer;
    let isRunning = false;

    const showNextItem = () => {
        if (!isRunning || !newsTextEl) return;

        const item = newsList[currentIndex];
        const text = typeof item === 'object' ? (item.text || "") : item;
        const category = typeof item === 'object' ? (item.category || "") : "";

        const labelText = (DEFAULT_WIPER || "").trim() || (category || "").trim();
        if (wiper) {
            wiper.style.display = labelText ? 'flex' : 'none';
            if (wiperTextEl) wiperTextEl.innerText = labelText;
        }

        gsap.to(newsTextEl, {
            y: -20, opacity: 0, duration: 0.4, ease: "power2.in",
            onComplete: () => {
                newsTextEl.innerText = text.toUpperCase();
                gsap.fromTo(newsTextEl, { y: 20, opacity: 0 }, { y: 0, opacity: 1, duration: 0.5, ease: "power2.out" });

                currentIndex = (currentIndex + 1) % newsList.length;
                const displayDuration = (parseFloat("{{TICKER_SPEED}}") || 5) * 1000;
                cycleTimer = setTimeout(showNextItem, displayDuration);
            }
        });
    };

    root.__slt_show = () => {
        isRunning = true;
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        tl.add(() => showNextItem(), "+ =0.1");
        return tl;
    };

    root.__slt_hide = () => {
        isRunning = false;
        if (cycleTimer) clearTimeout(cycleTimer);
        return GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
    };
})();
